#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define N 100005

int n, m, q, u, v;
int p[N], cnt[N], vis[N];

void dfs(int u) {
    vis[u] = 1;
    for (int i = 1; i <= cnt[u]; i++) {
        int v = p[u][i];
        if (!vis[v]) {
            dfs(v);
        } else if (v != p[u][1]) {
            printf("NO\n");
            return;
        }
    }
}

int main() {
    scanf("%d", &q);
    while (q--) {
        scanf("%d %d", &n, &m);
        for (int i = 1; i <= n; i++) {
            p[i] = (int *)malloc((m + 1) * sizeof(int));
            cnt[i] = 0;
        }
        for (int i = 1; i <= m; i++) {
            scanf("%d %d", &u, &v);
            p[u][++cnt[u]] = v;
            p[v][++cnt[v]] = u;
        }
        memset(vis, 0, sizeof(vis));
        dfs(1);
        printf("YES\n");
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= cnt[i]; j++) {
                printf("%d%c", p[i][j], j == cnt[i] ? '\n' : ' ');
            }
        }
    }
    return 0;
}

